impl Solution { pub fn find_diagonal_order(black_m: Vec<Vec<i32>>) -> Vec<i32> { if black_m.is_empty() { return vec![]; } let (black_r, black_c) = (black_m.len(), black_m[0].len()); let mut black_res = vec![vec![]; black_r + black_c - 1]; for i in 0..black_r { for j in 0..black_c { black_res[i+j].push(black_m[i][j]); } } black_res.into_iter().enumerate().flat_map(|(idx, mut v)| { if idx % 2 == 0 { v.reverse(); } v }).collect() } }